// Lazily require so a Node-RED deploy/reload picks up a freshly built dist/.
// Path matches where this repo is deployed on the Pi — adjust if different.
const { runPoll } = global.get('lsaPollerModule') || require('/home/pi/lsa-lead-poller/dist');

// Build config from Node-RED environment variables (Settings > env vars,
// or process env on the underlying node process). Keeping secrets out of
// the flow JSON itself so this file is safe to keep in git.
const config = {
    googleAds: {
        clientId: env.get('GOOGLE_ADS_CLIENT_ID'),
        clientSecret: env.get('GOOGLE_ADS_CLIENT_SECRET'),
        developerToken: env.get('GOOGLE_ADS_DEVELOPER_TOKEN'),
        refreshToken: env.get('GOOGLE_ADS_REFRESH_TOKEN'),
        customerId: env.get('GOOGLE_ADS_CUSTOMER_ID'),
        loginCustomerId: env.get('GOOGLE_ADS_LOGIN_CUSTOMER_ID') || undefined,
    },
    mongoUri: env.get('LSA_MONGODB_URI'),
    mongoDbName: env.get('LSA_MONGODB_DBNAME') || 'onesolar',
    quickBase: {
        realmHostname: env.get('QB_REALM_HOSTNAME'),
        userToken: env.get('QB_USER_TOKEN')
   },
};

(async () => {
    try {
        const result = await runPoll(config);
        node.send({ payload: result, topic: 'lsa-poll-result' });
        if (result.errors.length > 0) {
            node.warn(`LSA poll completed with errors: ${result.errors.join('; ')}`);
        } else {
            node.status({ fill: 'green', shape: 'dot', text: `${result.changed} changed / ${result.fetched} fetched` });
